previewCss:
.darma-loader-darma-custom-576 {color: var(--loader-color, #0284c7);
  --loader-secondary-color: var(--loader-secondary-color, #7dd3fc);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 28px;
   aspect-ratio: 1;
   border-radius: 50%;
   background: var(--loader-secondary-color, #7dd3fc);
   transform-origin: top;
   display: grid;
   animation: darma-loader-darma-custom-576-l3-0 1s infinite linear;
}
.darma-loader-darma-custom-576::before, .darma-loader-darma-custom-576::after  {
  content: "";
   grid-area: 1/1;
   background:var(--loader-secondary-color, #7dd3fc);
   border-radius: 50%;
   transform-origin: top;
   animation: inherit;
   animation-name: darma-loader-darma-custom-576-l3-1;
}
.darma-loader-darma-custom-576::after  {
  background: var(--loader-color, #0284c7);
   --s:180deg;
}
@keyframes darma-loader-darma-custom-576-l3-0  {
  0%,20% {transform: rotate(0)}
100% {transform: rotate(360deg)}
}
@keyframes darma-loader-darma-custom-576-l3-1  {
  50% {transform: rotate(var(--s,90deg))}
100% {transform: rotate(0)}
}

